#include<bits/stdc++.h>
using namespace std;
long long n,m,x[300010],y[300010],p,pt[300010][2];
long long ch[10500350][2],sum[10500350],tot,root[300010];
long long insert(long long pre,long long val)
{
    long long now=++tot,ans=now;
    for(long long i=31;i>=0;i--)
    {
        long long t=(val>>i)&1;
        ch[now][t^1]=ch[pre][t^1];
        pre=ch[pre][t];
        now=ch[now][t]=++tot;
        sum[now]=sum[pre]+1;
    }
    return ans;
}
long long solve(long long ax,long long bx,long long ay,long long by,long long k)
{
    k=(bx-ax+1)*(by-ay+1)-k+1;
    for(long long i=ax;i<=bx;i++)
    {
        pt[i][0]=root[ay-1];
        pt[i][1]=root[by];
    }
    long long ans=0;
    for(long long s=31;s>=0;s--)
    {
        long long cnt=0;
        for(long long i=ax;i<=bx;i++)
        {
            long long t=(x[i]>>s)&1;
            cnt+=sum[ch[pt[i][1]][t]]-sum[ch[pt[i][0]][t]];
        }
        long long nxt=(long long)(k>cnt);
        if(nxt)
        {
            k-=cnt;
        }
        ans=(ans<<1)|nxt;
        for(long long i=ax;i<=bx;i++)
        {
            long long t=((x[i]>>s)&1)^nxt;
            pt[i][0]=ch[pt[i][0]][t];
            pt[i][1]=ch[pt[i][1]][t];
        }
    }
    return ans;
}
int main()
{
    scanf("%lld%lld",&n,&m);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&x[i]);
    }
    for(long long i=1;i<=m;i++)
    {
        scanf("%lld",&y[i]);
        root[i]=insert(root[i-1],y[i]);
    }
    scanf("%lld",&p);
    while(p--)
    {
        long long u,d,l,r,k;
        scanf("%lld%lld%lld%lld%lld",&u,&d,&l,&r,&k);
        printf("%lld\n",solve(u,d,l,r,k));
    }
    return 0;
}
